"""
Generates a Caption for Figures for each Image which stands alone in a paragraph,
similar to pandoc#s handling of images/figures

Modified version of https://github.com/jdittrich/figureAltCaption that allows one extra line after
the image containging markdown.extensions.attr_list data `{: .. }`

--------------------------------------------

Licensed under the GPL 2 (see LICENSE.md)

Copyright 2015 - Jan Dittrich by
building upon the markdown-figures Plugin by
Copyright 2013 - [Helder Correia](http://heldercorreia.com) (GPL2)

Copyright 2018 - Tieto

--------------------------------------------

Examples:
    Bla bla bla

    ![this is the caption](http://lorempixel.com/400/200/)
    {: #figureid }

    Next paragraph starts here

would generate a figure like this:

    <figure id=figureid>
        <img src="http://lorempixel.com/400/200/">
        <figcaption>this is the caption</figcaption>
    </figure>
"""

from __future__ import unicode_literals
from markdown import Extension
import markdown.inlinepatterns as patterns
from markdown.blockprocessors import BlockProcessor
from markdown.util import etree
import re

import logging
logger = logging.getLogger('MARKDOWN')


class FigureCaptionProcessor(BlockProcessor):

    # Matches IMAGE_REFERENCE_RE and IMAGE_LINK_RE (simplified), then optionally {: ... }
    # ![alt text][2] or ![alt text](https://stuff)
    FIGURE_RE_STR = (r'^[ ]{0,3} ( \!' + patterns.BRK + r'\s*(  \[ [^]]* \] | \( [^)]* \) ))' +
            r'\s* (?P<attrs> \{: .* \} )? \s*$')
    # note: this is more permissive than what attr_list does now.
    FIGURE_RE = re.compile(FIGURE_RE_STR, re.VERBOSE | re.DOTALL)


    def test(self, parent, block):
        match = self.FIGURE_RE.match(block)
        if not match:
            return False
        self.img = match.group(1)
        self.caption = match.group(2) # comes from patterns.BRK
        self.attrs = match.group('attrs')

        # don't create figures with empty caption
        return self.caption and self.caption.strip()


    def run(self, parent, blocks):
        blocks.pop(0) # consume block

        figure = etree.SubElement(parent, 'figure')
        # this will be converted to <img>
        figure.text = self.img

        # this is caption
        figcaptionElem = etree.SubElement(figure,'figcaption')
        figcaptionElem.text =  self.caption

        # this will be picked by attr_list
        if self.attrs:
            figcaptionElem.tail = '\n\n' + self.attrs


class FigureCaptionExtension(Extension):
    def extendMarkdown(self, md, md_globals):
        md.parser.blockprocessors.add('figurecaption',
                                      FigureCaptionProcessor(md.parser),
                                      '>hr')


def makeExtension(configs={}):
    return FigureCaptionExtension(configs=configs)
